from __future__ import annotations


def _get_arcgis_notebooks_auth_lib():
    try:
        import arcgis_notebooks_auth
    except ImportError as e:
        raise ImportError(
            "The arcgis_notebooks_auth package is required to use notebook authentication; "
            "Please install it using `!conda install -c esri arcgis_notebooks_auth`"
        ) from e
    return arcgis_notebooks_auth


def get_value(encrypted_value: str, nbauth_file_path: str) -> str:
    """
    Decrypts the provided encrypted value using the arcgis_notebooks_auth library

    :param encrypted_value: The value to be decrypted
    :param nbauth_file_path: The file path to the nbauth.json file, used by the arcgis_notebooks_auth library to retrieve the decryption key
    :return: The decrypted value as a string
    """
    arcgis_notebooks_auth = _get_arcgis_notebooks_auth_lib()
    return arcgis_notebooks_auth.get_value(nbauth_file_path, "", encrypted_value)


def get_token(nb_auth_file_path: str) -> str:
    """
    Returns the token provided by the notebook server for authentication

    :return: str
    """
    arcgis_notebooks_auth = _get_arcgis_notebooks_auth_lib()
    return arcgis_notebooks_auth.get_token(nb_auth_file_path)
